import requests,re,json
html=requests.get('https://www.bbc.com/sport/football/teams/manchester-united/scores-fixtures',headers={'User-Agent':'Mozilla/5.0'},timeout=20).text
m=re.search(r'window\.__INITIAL_DATA__\s*=\s*({.*?});\s*</script>',html,re.S)
print('match',bool(m))
if not m:
 m=re.search(r'__INITIAL_DATA__"?\s*[:=]\s*({.*?})\s*;\s*</script>',html,re.S)
 print('match2',bool(m))
if m:
 txt=m.group(1)
 print('json len',len(txt))
 data=json.loads(txt)
 print(data.keys())
 # find containing fixtures
 def find_keys(obj, key, path=''):
  if isinstance(obj,dict):
   for k,v in obj.items():
    p=f'{path}.{k}' if path else k
    if key.lower() in k.lower():
      print(p,type(v).__name__)
    find_keys(v,key,p)
  elif isinstance(obj,list):
   for i,v in enumerate(obj[:5]):
    find_keys(v,key,f'{path}[{i}]')
 find_keys(data,'fixture')
 find_keys(data,'event')
PY"}

